#import "ModeView.h"
#import "PrefixHeader.h"

@interface ModeView ()

// 卡片容器
@property (nonatomic, strong) UIView *xueshanCard;
@property (nonatomic, strong) UIView *jingmiCard;
@property (nonatomic, strong) UIView *caoyuanCard;

// 每张卡片的主标题
@property (nonatomic, strong) UILabel *xueshanTitle;
@property (nonatomic, strong) UILabel *jingmiTitle;
@property (nonatomic, strong) UILabel *caoyuanTitle;

// 每张卡片的副标题
@property (nonatomic, strong) UILabel *xueshanSubtitle;
@property (nonatomic, strong) UILabel *jingmiSubtitle;
@property (nonatomic, strong) UILabel *caoyuanSubtitle;

