@property (nonatomic, strong) UIView *playBg1;
@property (nonatomic, strong) UIView *playBg2;
@property (nonatomic, strong) UIView *playBg3;

@end

@implementation ModeView

- (instancetype)init {
    self = [super init];
    if (self) {
        self.showsHorizontalScrollIndicator = NO;
        self.showsVerticalScrollIndicator = NO;
        [self setUpUI];
        [self modeShouldUpdate:self.xueshanbotton];
        self.scrollEnabled = YES;
    }
    return self;
}

- (void)layoutSubviews {
    [super layoutSubviews];
    CGFloat cardW = ZOOMW(300);
    CGFloat gap = ZOOMW(14);
    CGFloat totalWidth = cardW * 3 + gap * 2;
    self.contentSize = CGSizeMake(totalWidth, CGRectGetHeight(self.bounds));
}

#pragma mark - UI Events

- (void)modeShouldUpdate:(UIButton *)button {
    _xueshanbotton.selected = NO;
    _jingmibotton.selected = NO;
    _caoyuanbotton.selected = NO;

    button.selected = YES;

    // 隐藏所有播放按钮
    _playBg1.hidden = YES; _Selected1.hidden = YES;
    _playBg2.hidden = YES; _Selected2.hidden = YES;
    _playBg3.hidden = YES; _Selected3.hidden = YES;

    // 显示选中卡片的播放按钮
    if (button == _xueshanbotton) {
        _mode = @"钢琴音效.mp3";
        _playBg1.hidden = NO; _Selected1.hidden = NO;
    } else if (button == _jingmibotton) {
        _mode = @"钢琴:小提琴.mp3";
        _playBg2.hidden = NO; _Selected2.hidden = NO;
    } else if (button == _caoyuanbotton) {
        _mode = @"木吉他声.mp3";
        _playBg3.hidden = NO; _Selected3.hidden = NO;
    }
}

#pragma mark - Setup UI

- (void)setUpUI {
    self.backgroundColor = [UIColor clearColor];
    [self addAllSubviews];
    [self addAllConstraints];
}

- (void)addAllSubviews {
    // 卡片1 - 雪
    [self addSubview:self.xueshanCard];
    [_xueshanCard addSubview:self.xueshanTitle];
    [_xueshanCard addSubview:self.xueshanSubtitle];
    [_xueshanCard addSubview:self.xueshanbotton];
    [_xueshanCard addSubview:self.playBg1];
    [_xueshanCard addSubview:self.Selected1];

