    [_jingmiCard addSubview:self.jingmiTitle];
    [_jingmiCard addSubview:self.jingmiSubtitle];
    [_jingmiCard addSubview:self.jingmibotton];
    [_jingmiCard addSubview:self.playBg2];
    [_jingmiCard addSubview:self.Selected2];

    // 卡片3 - 草原
    [self addSubview:self.caoyuanCard];
    [_caoyuanCard addSubview:self.caoyuanTitle];
    [_caoyuanCard addSubview:self.caoyuanSubtitle];
    [_caoyuanCard addSubview:self.caoyuanbotton];
    [_caoyuanCard addSubview:self.playBg3];
    [_caoyuanCard addSubview:self.Selected3];
}

