- (void)addPlayerObserver {
    // 每隔0.1秒观察一次播放状态
    __weak typeof(self) weakSelf = self;
    [self.player addPeriodicTimeObserverForInterval:CMTimeMake(1, 10) queue:dispatch_get_main_queue() usingBlock:^(CMTime time) {
        if (weakSelf.player.rate != 0 && weakSelf.player.error == nil) {
            [weakSelf updateButtonPlayState:YES];
        } else {
            [weakSelf updateButtonPlayState:NO];
        }
    }];
}

- (void)togglePlayPause {
    if (self.player == nil || self.player.rate == 0.0) {
        // 确保有有效的播放资源
        if (_modeview.mode) {
            NSURL *url = [[NSBundle mainBundle] URLForResource:_modeview.mode withExtension:nil];
            if (url) {
                // 创建新的player实例
                self.player = [AVPlayer playerWithPlayerItem:[AVPlayerItem playerItemWithURL:url]];
                [self addPlayerObserver]; // 添加观察者

                // 请求权限以在后台播放音频，并允许与其它应用音频混合
                static dispatch_once_t onceToken;
                dispatch_once(&onceToken, ^{
                    AVAudioSession *audioSession = [AVAudioSession sharedInstance];
                    [audioSession setCategory:AVAudioSessionCategoryPlayback withOptions:AVAudioSessionCategoryOptionMixWithOthers error:nil];
                    [audioSession setActive:YES error:nil];
                });
                [self.player play];

                [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(runLoopTheMovie:) name:AVPlayerItemDidPlayToEndTimeNotification object:_player.currentItem];
            }
        }
    } else {
        // 暂停播放
        [self.player pause];
    }
}

- (void)playNextMode {
    // 停止当前播放
    [self.player pause];

    // 更新当前索引
    _currentModeIndex++;
    if (_currentModeIndex >= kPlayModes.count) {
        _currentModeIndex = 0;
    }

    // 获取下一个模式
    NSDictionary *mode = kPlayModes[_currentModeIndex];
    NSString *buttonName = mode[@"button"];

    // 手动触发按钮的选中状态
    [self selectModeButton:buttonName];

    // 播放对应的声音
    NSURL *url = [[NSBundle mainBundle] URLForResource:mode[@"file"] withExtension:nil];
    self.player = [AVPlayer playerWithPlayerItem:[AVPlayerItem playerItemWithURL:url]];
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        AVAudioSession *audioSession = [AVAudioSession sharedInstance];
        [audioSession setCategory:AVAudioSessionCategoryPlayback withOptions:AVAudioSessionCategoryOptionMixWithOthers error:nil];
        [audioSession setActive:YES error:nil];
    });
    [self addPlayerObserver]; // 添加观察者
    [self.player play];
}

